
import React, { useState, useEffect } from 'react';
import { Student, User, ViewState } from '../types';
import { DEFAULT_STUDENT_IMAGE } from '../constants';
import { calculateAge } from '../utils';

interface SGEStudent {
  id: string;
  profileImage: string;
  name: string;
  socialName: string;
  transgender: boolean;
  classroom: string;
  birthDate: string;
  pcdInfo: string;
  monthSeverity: number;
}

interface StudentListProps {
  currentUser: User | null;
  onNavigate: (view: ViewState, studentIds?: string[]) => void;
}

const StudentList: React.FC<StudentListProps> = ({ currentUser, onNavigate }) => {
  const [students, setStudents] = useState<SGEStudent[]>([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  const [loading, setLoading] = useState(true);

  const fetchStudents = async (search: string = '') => {
    setLoading(true);
    try {
      console.log(`Fetching students with search: "${search}"`);
      const res = await fetch(`/api/students?mode=list&search=${encodeURIComponent(search)}`);
      if (res.ok) {
        const data = await res.json();
        console.log(`Fetched ${data.length} students`);
        setStudents(data);
      } else {
        const errorData = await res.json();
        console.error("API Error:", errorData);
      }
    } catch (err) {
      console.error("Error fetching active students:", err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchStudents(searchTerm);
  }, [searchTerm]);

  const toggleSelection = (id: string) => {
    setSelectedIds(prev => 
      prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]
    );
  };

  const getSeverityColor = (severity: number) => {
    if (severity === 3) return 'text-red-600';
    if (severity === 2) return 'text-amber-600';
    if (severity === 1) return 'text-green-600';
    return 'text-slate-600';
  };

  return (
    <div className="p-4 space-y-4 relative min-h-full font-sans">
      <div className="relative">
        <input 
          type="text" 
          placeholder="Buscar por nome ou turma..." 
          className="w-full pl-4 pr-10 py-3 border border-slate-200 rounded-2xl bg-white shadow-sm focus:ring-2 focus:ring-indigo-500 outline-none uppercase" 
          value={searchTerm} 
          onChange={(e) => setSearchTerm(e.target.value)} 
        />
        <span className="absolute inset-y-0 right-0 pr-4 flex items-center text-slate-400">
          <i className="fas fa-search"></i>
        </span>
      </div>

      {selectedIds.length > 0 && (
        <div className="animate-fade-in">
          <button 
            onClick={() => onNavigate('ADD_OCCURRENCE', selectedIds)}
            className="w-full bg-orange-400 text-white py-4 rounded-2xl font-bold shadow-lg flex items-center justify-center space-x-3 active:scale-[0.98] transition-all"
          >
            <i className="fas fa-clipboard-list"></i>
            <span>Registrar Ocorrência({selectedIds.length})</span>
          </button>
        </div>
      )}

      <div className="space-y-3 pb-20">
        {loading ? (
          <div className="flex justify-center py-10">
            <div className="w-8 h-8 border-4 border-indigo-100 border-t-indigo-600 rounded-full animate-spin"></div>
          </div>
        ) : students.length > 0 ? (
          students.map(student => {
            const isSelected = selectedIds.includes(student.id);
            const displayName = student.socialName || student.name;
            const age = calculateAge(student.birthDate);
            
            return (
              <div 
                key={student.id} 
                onClick={() => toggleSelection(student.id)}
                className={`p-4 rounded-2xl border flex items-center space-x-4 cursor-pointer transition-all ${
                  isSelected ? 'bg-red-50 border-red-100 shadow-md' : 'bg-emerald-50 border-slate-100 shadow-sm hover:border-indigo-200'
                }`}
              >
                <img 
                  src={student.profileImage || DEFAULT_STUDENT_IMAGE} 
                  alt={displayName} 
                  className="w-14 h-14 rounded-full object-cover border-2 border-slate-50 shadow-sm"
                  referrerPolicy="no-referrer"
                />
                <div className="flex-1 min-w-0">
                  <div className="flex items-center space-x-2">
                    <h3 className={`font-bold truncate ${getSeverityColor(student.monthSeverity)}`}>
                      {displayName}
                    </h3>
                    <div className="flex space-x-1">
                      {student.transgender && (
                        <img src="data:image/png;base64," alt="Trans" className="w-4 h-4" title="Nome Social / Transgênero" />
                      )}
                      {student.pcd_info && student.pcd_info !== '' && (
                        <img src="data:image/png;base64," alt="PCD" className="w-4 h-4" title={`PCD: ${student.pcd_info}`} />
                      )}
                    </div>
                  </div>
                  <p className="text-xs text-slate-500 font-medium">
                    {age} Anos • {student.classroom}
                  </p>
                </div>
                {isSelected && (
                  <div className="w-6 h-6 bg-orange-600 rounded-full flex items-center justify-center text-white shadow-sm">
                    <i className="fas fa-check text-[10px]"></i>
                  </div>
                )}
              </div>
            );
          })
        ) : (
          <div className="text-center py-20 px-6 space-y-4">
            <div className="w-20 h-20 bg-slate-100 rounded-full flex items-center justify-center mx-auto text-slate-300">
              <i className="fas fa-users text-3xl"></i>
            </div>
            <div className="space-y-2">
              <p className="text-slate-500 font-bold">Nenhum aluno encontrado</p>
              <p className="text-slate-400 text-xs leading-relaxed">
                Certifique-se de que a sincronização com o SGE foi realizada no menu de Gerenciamento do Sistema.
              </p>
            </div>
            <button 
              onClick={() => fetchStudents(searchTerm)}
              className="text-indigo-600 text-sm font-bold hover:underline"
            >
              Tentar novamente
            </button>
          </div>
        )}
      </div>
    </div>
  );
};

export default StudentList;
